using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer;

/// <summary>
/// MCP tools that wrap a REST API via HttpClient.
/// Non-static class — the SDK injects constructor dependencies automatically.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("List all items from the API.")]
    public async Task<string> ListItems(CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing all items");
        var json = await httpClient.GetStringAsync("/items", cancellationToken);
        return json;
    }

    [McpServerTool, Description("Get a single item by its unique identifier.")]
    public async Task<string> GetItem(
        [Description("The unique identifier of the item to retrieve")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Getting item {Id}", id);
        var response = await httpClient.GetAsync($"/items/{id}", cancellationToken);

        if (!response.IsSuccessStatusCode)
        {
            return $"Error: API returned {(int)response.StatusCode} {response.ReasonPhrase}";
        }

        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Create a new item with the given name and optional description.")]
    public async Task<string> CreateItem(
        [Description("Name for the new item")] string name,
        [Description("Optional description of the item")] string? description = null,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating item {Name}", name);

        var payload = JsonSerializer.Serialize(new { name, description }, JsonOptions);
        var content = new StringContent(payload, System.Text.Encoding.UTF8, "application/json");
        var response = await httpClient.PostAsync("/items", content, cancellationToken);

        if (!response.IsSuccessStatusCode)
        {
            return $"Error: API returned {(int)response.StatusCode} {response.ReasonPhrase}";
        }

        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

